     1→/**
     2→ * Mens HRT Enhanced PDP 1
     3→ * Page-specific styles for page-mens-hrt-enhanced-pdp.php
     4→ *
     5→ * Desktop-first: base styles target desktop (1440px).
     6→ * Tablet/mobile overrides via $medium-screen-and-smaller (max-width: 1024px).
     7→ * Mobile-only refinements via $small-screen-only (max-width: 600px).
     8→ */
     9→@use '../variables/colors' as colors;
    10→@use '../variables/fonts' as fonts;
    11→@use '../variables/layout' as layout;
    12→
    13→.mens-hrt-enhanced-pdp-1 {
    14→
    15→	> *:not(.linkbar, .navbar, .site-footer) > .container {
    16→		max-width: 1440px;
    17→		margin: 0 auto;
    18→	}
    19→	.extended-center-border-above,
    20→	.extended-center-border-below {
    21→		@media #{layout.$medium-screen-and-smaller} {
    22→			&::before,
    23→			&::after {
    24→				display: none !important;
    25→			}
    26→		}
    27→	}
    28→
    29→	/*
    30→	* =============================
    31→	* Hero
    32→	* =============================
    33→	*/
    34→	.boost-your-testosterone.hero {
    35→		background-color: colors.$color-white;
    36→		padding: fonts.rem(40px) fonts.rem(64px);
    37→		@media #{layout.$medium-screen-and-smaller} {
    38→			padding: fonts.rem(16px) fonts.rem(32px) fonts.rem(40px);
    39→			flex-direction: column;
    40→			gap: fonts.rem(24px);
    41→		}
    42→		@media #{layout.$small-screen-only} {
    43→			padding-inline: fonts.rem(16px);
    44→		}
    45→
    46→		.container.grid {
    47→			gap: fonts.rem(64px);
    48→			grid-template-columns: 600px 1fr;
    49→			@media #{layout.$medium-screen-and-smaller} {
    50→				grid-template-columns: 1fr;
    51→				gap: fonts.rem(24px);
    52→			}
    53→		}
    54→
    55→		.container {
    56→			@media #{layout.$medium-screen-and-smaller} {
    57→				display: flex;
    58→				flex-direction: column;
    59→				gap: fonts.rem(24px);
    60→			}
    61→		}
    62→
    63→		// Left column — image
    64→		.media-wrapper {
    65→			padding: 0;
    66→			display: flex;
    67→			align-items: center;
    68→			background-color: colors.$color-white;
    69→			@media #{layout.$medium-screen-and-smaller} {
    70→				order: 1;
    71→			}
    72→
    73→			.media-block {
    74→				width: 600px;
    75→				aspect-ratio: 1 / 1;
    76→				@media #{layout.$medium-screen-and-smaller} {
    77→					width: 100%;
    78→					max-width: fonts.rem(600px);
    79→					height: auto;
    80→					margin-left: auto;
    81→					margin-right: auto;
    82→				}
    83→
    84→				video {
    85→					width: 100%;
    86→					height: 100%;
    87→					object-fit: cover;
    88→				}
    89→			}
    90→		}
    91→
    92→		// Right column — content
    93→		.content-wrapper {
    94→			padding: 0;
    95→			display: flex;
    96→			flex-direction: column;
    97→			justify-content: center;
    98→			gap: fonts.rem(40px);
    99→			@media #{layout.$medium-screen-and-smaller} {
   100→				order: 2;
   101→				gap: fonts.rem(24px);
   102→			}
   103→
   104→			// Title
   105→			.title-block h2 {
   106→				font-family: fonts.$STIX-Two-Text;
   107→				font-weight: 400;
   108→				font-size: fonts.rem(54px);
   109→				line-height: 1;
   110→				letter-spacing: -1.08px;
   111→				color: colors.$color-black;
   112→				max-width: 576px;
   113→				@media #{layout.$medium-screen-and-smaller} {
   114→					font-size: fonts.rem(36px);
   115→					letter-spacing: -0.72px;
   116→					max-width: none;
   117→				}
   118→			}
   119→
   120→			// List items
   121→			.content-block {
   122→				ul {
   123→					list-style: none;
   124→					margin: 0;
   125→					padding: 0;
   126→					display: flex;
   127→					flex-direction: column;
   128→					gap: fonts.rem(16px);
   129→					@media #{layout.$medium-screen-and-smaller} {
   130→						gap: fonts.rem(12px);
   131→					}
   132→				}
   133→
   134→				li {
   135→					border-left: 2px solid rgba(96, 91, 82, 0.2);
   136→					padding-left: fonts.rem(12px);
   137→					font-family: fonts.$DM-Sans;
   138→					font-weight: 500;
   139→					font-size: fonts.rem(22px);
   140→					line-height: 1.1;
   141→					letter-spacing: -0.44px;
   142→					color: colors.$color-black;
   143→					@media #{layout.$medium-screen-and-smaller} {
   144→						font-size: fonts.rem(18px);
   145→						letter-spacing: -0.36px;
   146→						padding-left: fonts.rem(8px);
   147→					}
   148→				}
   149→			}
   150→
   151→			// CTA block
   152→			.cta-block {
   153→				display: flex;
   154→				flex-direction: column;
   155→				gap: fonts.rem(8px);
   156→				width: 100%;
   157→
   158→				.cta-wrapper {
   159→					width: 100%;
   160→				}
   161→
   162→				a {
   163→					width: 100%;
   164→					height: 48px;
   165→					border-radius: 2px;
   166→					padding: 0 fonts.rem(48px);
   167→					box-sizing: border-box;
   168→				}
   169→			}
   170→
   171→			// Badges — pull up to 8px below CTA (40px gap - 32px = 8px)
   172→			.badges-wrapper {
   173→				margin-top: fonts.rem(-32px);
   174→				display: flex;
   175→				flex-wrap: wrap;
   176→				align-items: center;
   177→				justify-content: center;
   178→				gap: fonts.rem(10px);
   179→				// Adjust for 24px gap (24px - 16px = 8px)
   180→				@media #{layout.$medium-screen-and-smaller} {
   181→					margin-top: fonts.rem(-16px);
   182→				}
   183→
   184→				.badge {
   185→					display: flex;
   186→					align-items: center;
   187→					height: 20px;
   188→
   189→					img {
   190→						width: auto;
   191→						height: 24px;
   192→					}
   193→
   194→					span {
   195→						font-family: fonts.$DM-Sans;
   196→						font-weight: 400;
   197→						font-size: fonts.rem(14px);
   198→						line-height: 1.4;
   199→						letter-spacing: -0.28px;
   200→						color: colors.$color-gray;
   201→						text-align: center;
   202→					}
   203→				}
   204→			}
   205→		}
   206→	}
   207→
   208→	/*
   209→	* =============================
   210→	* Marquee / Trustpilot Ratings
   211→	* =============================
   212→	*/
   213→	.marquee.trustpilot-ratings {
   214→		background-color: colors.$color-white;
   215→
   216→		.container {
   217→			display: flex;
   218→			align-items: center;
   219→			gap: fonts.rem(16px);
   220→			padding: fonts.rem(16px);
   221→			@media #{layout.$medium-screen-and-smaller} {
   222→				flex-direction: column;
   223→				padding: fonts.rem(16px) 0;
   224→			}
   225→		}
   226→
   227→		.trustpilot-wrapper {
   228→			flex-shrink: 0;
   229→			@media only screen and (max-width: 445px) {
   230→				min-width: unset;
   231→			}
   232→		}
   233→
   234→		.trustpilot-static {
   235→			display: flex;
   236→			align-items: center;
   237→			gap: fonts.rem(8px);
   238→			text-decoration: none;
   239→			color: #191919;
   240→			white-space: nowrap;
   241→
   242→			.tp-text {
   243→				font-weight: 700;
   244→				font-size: fonts.rem(12px);
   245→			}
   246→
   247→			.tp-stars {
   248→				height: 14px;
   249→			}
   250→
   251→			.tp-count {
   252→				font-size: fonts.rem(12px);
   253→			}
   254→
   255→			.tp-brandmark {
   256→				width: auto;
   257→				height: 16px;
   258→			}
   259→
   260→			@media only screen and (max-width: 445px) {
   261→				flex-wrap: wrap;
   262→				justify-content: center;
   263→				gap: fonts.rem(4px) fonts.rem(8px);
   264→			}
   265→		}
   266→
   267→		.reviews-wrapper {
   268→			flex: 1 0 0;
   269→			overflow: hidden;
   270→			position: relative;
   271→			@media #{layout.$medium-screen-and-smaller} {
   272→				flex: 0 0 auto;
   273→				width: 100%;
   274→			}
   275→
   276→			// Fade edges
   277→			&::before,
   278→			&::after {
   279→				content: '';
   280→				position: absolute;
   281→				top: 0;
   282→				bottom: 0;
   283→				width: 78px;
   284→				z-index: 1;
   285→				pointer-events: none;
   286→			}
   287→
   288→			&::before {
   289→				left: 0;
   290→				background: linear-gradient(to right, colors.$color-white, transparent);
   291→			}
   292→
   293→			&::after {
   294→				right: 0;
   295→				background: linear-gradient(to left, colors.$color-white, transparent);
   296→			}
   297→		}
   298→
   299→		.reviews-marquee {
   300→			display: flex;
   301→			gap: fonts.rem(16px);
   302→			white-space: nowrap;
   303→			animation: marquee-scroll calc(var(--review-count, 4) * 1s) linear infinite;
   304→		}
   305→
   306→		.review-item {
   307→			display: flex;
   308→			align-items: center;
   309→			gap: fonts.rem(8px);
   310→			flex-shrink: 0;
   311→
   312→			.quote-content {
   313→				font-family: fonts.$DM-Sans;
   314→				font-weight: 400;
   315→				font-size: fonts.rem(16px);
   316→				line-height: 1.4;
   317→				letter-spacing: -0.16px;
   318→				color: colors.$color-black;
   319→			}
   320→
   321→			.reviewer-details {
   322→				font-family: fonts.$DM-Sans;
   323→				font-weight: 400;
   324→				font-size: fonts.rem(16px);
   325→				line-height: 1.4;
   326→				letter-spacing: -0.16px;
   327→				color: colors.$color-gray;
   328→			}
   329→		}
   330→	}
   331→
   332→	/*
   333→	* =============================
   334→	* How It Works / Social Videos
   335→	* =============================
   336→	*/
   337→	.how-it-works.social-videos {
   338→		padding: fonts.rem(64px) 0;
   339→		position: relative;
   340→		@media #{layout.$medium-screen-and-smaller} {
   341→			padding: fonts.rem(40px) 0;
   342→		}
   343→
   344→		&.extended-center-border-below::after {
   345→			left: 50%;
   346→		}
   347→
   348→		&::before {
   349→			@media #{layout.$medium-screen-and-smaller} {
   350→				display: none;
   351→			}
   352→		}
   353→
   354→		.container {
   355→			position: relative;
   356→			z-index: 1;
   357→			background-color: colors.$color-white;
   358→			border-radius: 20px;
   359→			padding: fonts.rem(32px) 0;
   360→			display: flex;
   361→			flex-direction: column;
   362→			gap: fonts.rem(32px);
   363→			@media #{layout.$medium-screen-and-smaller} {
   364→				padding: 0;
   365→				border-radius: 0;
   366→				background-color: transparent;
   367→			}
   368→		}
   369→
   370→		// Title block
   371→		.title-wrapper {
   372→			display: flex;
   373→			flex-direction: column;
   374→			gap: fonts.rem(16px);
   375→			align-items: center;
   376→			text-align: center;
   377→			@media #{layout.$medium-screen-and-smaller} {
   378→				gap: fonts.rem(8px);
   379→			}
   380→
   381→			.title {
   382→				font-family: fonts.$STIX-Two-Text;
   383→				font-weight: 400;
   384→				font-size: fonts.rem(54px);
   385→				line-height: 1;
   386→				letter-spacing: -1.08px;
   387→				color: colors.$color-black;
   388→				@media #{layout.$medium-screen-and-smaller} {
   389→					font-size: fonts.rem(36px);
   390→					letter-spacing: -0.72px;
   391→				}
   392→			}
   393→
   394→			.subtitle {
   395→				font-family: fonts.$DM-Sans;
   396→				font-weight: 500;
   397→				font-size: fonts.rem(22px);
   398→				line-height: 1;
   399→				letter-spacing: -0.44px;
   400→				color: colors.$color-black;
   401→				@media #{layout.$medium-screen-and-smaller} {
   402→					font-size: fonts.rem(18px);
   403→					letter-spacing: -0.36px;
   404→				}
   405→			}
   406→		}
   407→
   408→		// Video cards row
   409→		.carousel-wrapper {
   410→			padding: 0;
   411→			display: flex;
   412→			gap: fonts.rem(24px);
   413→			align-items: center;
   414→			justify-content: center;
   415→			@media #{layout.$medium-screen-and-smaller} {
   416→				gap: fonts.rem(8px);
   417→				justify-content: flex-start;
   418→				overflow-x: auto;
   419→				-webkit-overflow-scrolling: touch;
   420→				scrollbar-width: none;
   421→
   422→				&::-webkit-scrollbar {
   423→					display: none;
   424→				}
   425→			}
   426→			.review-video-item:first-child {
   427→				margin-left: fonts.rem(32px);
   428→				@media #{layout.$small-screen-only} {
   429→					margin-left: fonts.rem(16px);
   430→				}
   431→			}
   432→			.review-video-item:last-child {
   433→				margin-right: fonts.rem(32px);
   434→				@media #{layout.$small-screen-only} {
   435→					margin-right: fonts.rem(16px);
   436→				}
   437→			}
   438→		}
   439→
   440→		.review-video-item {
   441→			width: 270px;
   442→			height: 480px;
   443→			border-radius: 20px;
   444→			overflow: hidden;
   445→			position: relative;
   446→			background-color: colors.$color-gray-light;
   447→			flex-shrink: 0;
   448→			cursor: pointer;
   449→
   450→			.thumbnail-wrapper {
   451→				position: absolute;
   452→				inset: 0;
   453→				z-index: 1;
   454→				transition: opacity 0.3s ease;
   455→
   456→				img {
   457→					width: 100%;
   458→					height: 100%;
   459→					object-fit: cover;
   460→				}
   461→			}
   462→
   463→			.video-wrapper {
   464→				position: absolute;
   465→				inset: 0;
   466→
   467→				video {
   468→					width: 100%;
   469→					height: 100%;
   470→					object-fit: cover;
   471→				}
   472→			}
   473→
   474→		.play-button {
   475→			position: absolute;
   476→			top: 50%;
   477→			left: 50%;
   478→			transform: translate(-50%, -50%);
   479→			z-index: 2;
   480→			width: 72px;
   481→			height: 72px;
   482→			border-radius: 50%;
   483→			border: none;
   484→			background: rgba(255, 255, 255, 0.75);
   485→			color: rgba(0, 0, 0, 0.75);
   486→			cursor: pointer;
   487→			display: flex;
   488→			align-items: center;
   489→			justify-content: center;
   490→			transition: opacity 0.3s ease, background 0.2s ease;
   491→			pointer-events: none;
   492→
   493→			svg {
   494→				margin-left: 3px;
   495→				fill: rgba(0, 0, 0, 0.4);
   496→			}
   497→
   498→			&:hover {
   499→				background: rgba(255, 255, 255, 0.9);
   500→			}
   501→		}
   502→
   503→		&.playing .play-button {
   504→			opacity: 0;
   505→		}
   506→
   507→		.mute-toggle {
   508→			position: absolute;
   509→			bottom: 12px;
   510→			right: 12px;
   511→			z-index: 3;
   512→			width: 36px;
   513→			height: 36px;
   514→			border-radius: 50%;
   515→			border: none;
   516→			background: rgba(0, 0, 0, 0.55);
   517→			color: colors.$color-white;
   518→			cursor: pointer;
   519→			display: flex;
   520→			align-items: center;
   521→			justify-content: center;
   522→			opacity: 0;
   523→			transition: opacity 0.3s ease, background 0.2s ease;
   524→			padding: 0;
   525→
   526→			&:hover {
   527→				background: rgba(0, 0, 0, 0.75);
   528→			}
   529→
   530→			.icon-unmuted {
   531→				display: none;
   532→			}
   533→		}
   534→
   535→		&.playing .thumbnail-wrapper {
   536→			opacity: 0;
   537→		}
   538→
   539→		&.playing .mute-toggle {
   540→			opacity: 1;
   541→		}
   542→
   543→		&.unmuted .mute-toggle {
   544→			.icon-muted {
   545→				display: none;
   546→			}
   547→			.icon-unmuted {
   548→				display: block;
   549→			}
   550→		}
   551→	}
   552→	}
   553→
   554→	/*
   555→	* =============================
   556→	* Benefits Timeline
   557→	* =============================
   558→	*/
   559→	.benefits-timeline {
   560→		background-color: colors.$color-white;
   561→		padding: fonts.rem(32px) 0;
   562→		position: relative;
   563→		@media #{layout.$medium-screen-and-smaller} {
   564→			padding: fonts.rem(40px) 0;
   565→		}
   566→
   567→		.container {
   568→			position: relative;
   569→			z-index: 1;
   570→			background-color: colors.$color-white;
   571→			display: flex;
   572→			flex-direction: column;
   573→			gap: fonts.rem(32px);
   574→			padding: fonts.rem(32px) 0 fonts.rem(80px);
   575→			@media #{layout.$medium-screen-and-smaller} {
   576→				padding: 0;
   577→				gap: fonts.rem(40px);
   578→				padding: 0;
   579→				background-color: transparent;
   580→			}
   581→		}
   582→
   583→		// Title
   584→		.title-block {
   585→			text-align: center;
   586→
   587→			.title {
   588→				font-family: fonts.$STIX-Two-Text;
   589→				font-weight: 400;
   590→				font-size: fonts.rem(54px);
   591→				line-height: 1;
   592→				letter-spacing: -1.08px;
   593→				color: colors.$color-black;
   594→				@media #{layout.$medium-screen-and-smaller} {
   595→					font-size: fonts.rem(36px);
   596→					letter-spacing: -0.72px;
   597→				}
   598→			}
   599→		}
   600→
   601→		// Cards row
   602→		.timeline-wrapper {
   603→			padding: 0;
   604→		}
   605→
   606→		.benefits-timeline-carousel {
   607→			display: flex;
   608→			justify-content: center;
   609→			align-items: stretch; // all cards same height so dividers align
   610→			width: 100%;
   611→			@media #{layout.$medium-screen-and-smaller} {
   612→				justify-content: flex-start;
   613→				overflow-x: auto;
   614→				-webkit-overflow-scrolling: touch;
   615→				scrollbar-width: none;
   616→
   617→				&::-webkit-scrollbar {
   618→					display: none;
   619→				}
   620→			}
   621→		}
   622→
   623→		// Individual card
   624→		// Image has fixed height so the divider line stays at a constant
   625→		// vertical position across all cards during expand/collapse.
   626→		.timeline-card {
   627→			display: flex;
   628→			flex-direction: column;
   629→			gap: fonts.rem(8px);
   630→			width: 250px;
   631→			flex-shrink: 0;
   632→			opacity: 0.8;
   633→			cursor: pointer;
   634→			transition: width 0.4s ease, opacity 0.4s ease;
   635→			@media #{layout.$medium-screen-and-smaller} {
   636→				max-width: 325px;
   637→				width: 100vw;
   638→				opacity: 1;
   639→				cursor: default;
   640→				transition: none;
   641→			}
   642→			&:first-child {
   643→				margin-left: fonts.rem(32px);
   644→				@media #{layout.$small-screen-only} {
   645→					margin-left: fonts.rem(16px);
   646→				}
   647→				@media only screen and (max-width: 315px) {
   648→					margin-left: fonts.rem(8px);
   649→				}
   650→			}
   651→			&:last-child {
   652→				margin-right: fonts.rem(32px);
   653→				@media #{layout.$small-screen-only} {
   654→					margin-right: fonts.rem(16px);
