			// Image — fixed height, image sits at the bottom
			.image-wrapper {
				padding: 0 fonts.rem(8px);
				height: 296px;
				display: flex;
				align-items: flex-end;
				@media #{layout.$medium-screen-and-smaller} {
					height: auto;
					align-items: stretch;
				}

				img {
					width: 100%;
					aspect-ratio: 1 / 1;
					object-fit: cover;
					border-radius: 15px;
					display: block;
					transition: border-radius 0.4s ease;
					@media #{layout.$medium-screen-and-smaller} {
						border-radius: 20px;
					}
				}
			}

			// Divider: dot + line — the anchored midline
			.divider-wrapper {
				display: flex;
				align-items: center;
				gap: fonts.rem(8px);
				padding-bottom: fonts.rem(8px);
				padding-left: fonts.rem(8px);

				.dot {
					width: 12px;
					height: 12px;
					border-radius: 8px;
					border: 3px solid #20C475;
					background: colors.$color-white;
					flex-shrink: 0;
					box-sizing: border-box;
					// @media #{layout.$medium-screen-and-smaller} {
					// 	border-color: colors.$color-gray;
					// 	background: #D9D9D9;
					// }
				}

				.line {
					flex: 1;
					height: 1px;
					background-color: colors.$color-gray;
				}
			}

			// Content: day, heading, body
			.content-wrapper {
				display: flex;
				flex-direction: column;
				gap: fonts.rem(8px);
				padding: 0 fonts.rem(8px);

				.day {
					font-family: fonts.$DM-Sans;
					font-weight: 400;
					font-size: fonts.rem(14px);
					line-height: 1.1;
					letter-spacing: -0.28px;
					color: colors.$color-black;
				}

				.heading {
					font-family: fonts.$DM-Sans;
					font-weight: 500;
					font-size: fonts.rem(18px);
					line-height: 1.1;
					letter-spacing: -0.36px;
					color: colors.$color-black;
					max-height: 0;
					overflow: hidden;
					opacity: 0;
					transition: max-height 0.4s ease, opacity 0.3s ease;
					@media #{layout.$medium-screen-and-smaller} {
						max-height: none;
						overflow: visible;
						opacity: 1;
					}
				}

				.body {
					font-family: fonts.$DM-Sans;
					font-weight: 400;
					font-size: fonts.rem(14px);
					line-height: 1.4;
					letter-spacing: -0.14px;
					color: colors.$color-black;
					max-height: 0;
					overflow: hidden;
					opacity: 0;
					transition: max-height 0.4s ease, opacity 0.3s ease;
					@media #{layout.$medium-screen-and-smaller} {
						max-height: none;
						overflow: visible;
						opacity: 1;
					}
				}
			}

			// Active state
			&.active {
				width: 312px;
				opacity: 1;
				@media #{layout.$medium-screen-and-smaller} {
					max-width: 325px;
					width: 100vw;
				}

				.image-wrapper img {
					border-radius: 22.5px;
					@media #{layout.$medium-screen-and-smaller} {
						border-radius: 20px;
					}
				}

				.content-wrapper {
					.heading {
						max-height: 100px;
						opacity: 1;
					}

					.body {
						max-height: 300px;
						opacity: 1;
					}
				}
			}
		}
	}

